using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

var builder = Host.CreateApplicationBuilder(args);

builder.Services.AddChatClient(chatClientBuilder =>
    chatClientBuilder.UseOpenAIChatClient(
        builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18"));

builder.Services.AddSingleton<ResearchTools>();
builder.Services.AddSingleton<Notebook>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var researchTools = host.Services.GetRequiredService<ResearchTools>();
var notebook = host.Services.GetRequiredService<Notebook>();

var tools = new AITool[]
{
    AIFunctionFactory.Create(researchTools.SearchWebAsync),
    AIFunctionFactory.Create(researchTools.FetchPageAsync),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An AI agent that researches topics by searching the web and taking notes.",
    instructions: """
        You are a research assistant. When given a topic:
        1. Search the web for relevant information using multiple queries.
        2. Fetch promising pages for deeper reading.
        3. Save important findings as notes using the note-taking tool.
        4. After gathering enough information, retrieve all your notes and produce a
           well-structured summary with key findings and sources.
        Be thorough but concise. Always cite your sources.
        """,
    tools: tools);

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent (MAF)        ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a research topic (or 'quit' to exit): ");

while (Console.ReadLine() is { } input && !input.Equals("quit", StringComparison.OrdinalIgnoreCase))
{
    if (string.IsNullOrWhiteSpace(input))
    {
        Console.Write("\nEnter a research topic: ");
        continue;
    }

    notebook.Clear();
    Console.WriteLine($"\nResearching: {input}\n");

    var session = await agent.CreateSessionAsync();
    var runOptions = new ChatClientAgentRunOptions(new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    });

    try
    {
        await foreach (var update in agent.RunStreamingAsync(input, session, runOptions))
        {
            Console.Write(update.Text);
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\nError: {ex.Message}");
        Console.WriteLine("Ensure the AI:ApiKey and AI:ModelId are configured.");
    }

    Console.WriteLine("\n");
    Console.Write("Enter a research topic (or 'quit' to exit): ");
}

Console.WriteLine("Goodbye!");

// --- Tool definitions ---

/// <summary>Provides web search and page-fetching tools for the research agent.</summary>
public sealed class ResearchTools
{
    private static readonly HttpClient s_httpClient = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
    };

    [Description("Searches the web for the given query and returns a list of result titles, snippets, and URLs.")]
    public static async Task<IReadOnlyList<SearchResult>> SearchWebAsync(
        [Description("The search query to look up.")] string query,
        [Description("Maximum number of results to return (1-10).")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await s_httpClient.GetStringAsync(url);

            var results = new List<SearchResult>();
            var resultSpan = html.AsSpan();
            var searchIndex = 0;

            while (results.Count < maxResults)
            {
                var snippetStart = resultSpan[searchIndex..].IndexOf("class=\"result__snippet\"");
                if (snippetStart < 0) break;
                snippetStart += searchIndex;

                var linkStart = resultSpan[searchIndex..].IndexOf("class=\"result__a\"");
                if (linkStart < 0) break;
                linkStart += searchIndex;

                var title = ExtractTagContent(resultSpan, linkStart);
                var snippet = ExtractTagContent(resultSpan, snippetStart);

                var hrefStart = resultSpan[linkStart..].IndexOf("href=\"");
                string resultUrl = "";
                if (hrefStart >= 0)
                {
                    var hrefContent = resultSpan[(linkStart + hrefStart + 6)..];
                    var hrefEnd = hrefContent.IndexOf('"');
                    if (hrefEnd > 0)
                    {
                        resultUrl = hrefContent[..hrefEnd].ToString();
                        if (resultUrl.StartsWith("//duckduckgo.com/l/?uddg="))
                        {
                            resultUrl = Uri.UnescapeDataString(
                                resultUrl["//duckduckgo.com/l/?uddg=".Length..].Split('&')[0]);
                        }
                    }
                }

                if (!string.IsNullOrWhiteSpace(title))
                {
                    results.Add(new SearchResult(
                        StripHtml(title),
                        StripHtml(snippet),
                        resultUrl));
                }

                searchIndex = Math.Max(snippetStart, linkStart) + 1;
            }

            return results.Count > 0
                ? results
                : [new SearchResult("No results found", $"No web results found for: {query}", "")];
        }
        catch (Exception ex)
        {
            return [new SearchResult("Search error", ex.Message, "")];
        }
    }

    [Description("Fetches the text content of a web page at the given URL. Returns the first ~3000 characters.")]
    public static async Task<string> FetchPageAsync(
        [Description("The URL of the web page to fetch.")] string url)
    {
        try
        {
            var html = await s_httpClient.GetStringAsync(url);

            // Crude HTML-to-text: strip tags, collapse whitespace
            var text = StripHtml(html);
            return text.Length > 3000 ? text[..3000] + "\n[...truncated]" : text;
        }
        catch (Exception ex)
        {
            return $"Error fetching page: {ex.Message}";
        }
    }

    private static string ExtractTagContent(ReadOnlySpan<char> html, int attrPos)
    {
        var closeAngle = html[attrPos..].IndexOf('>');
        if (closeAngle < 0) return "";
        var contentStart = attrPos + closeAngle + 1;
        var endTag = html[contentStart..].IndexOf('<');
        if (endTag < 0) return html[contentStart..].ToString();
        return html[contentStart..(contentStart + endTag)].ToString();
    }

    private static string StripHtml(string html)
    {
        // Remove script/style blocks, then tags, then decode entities
        var text = System.Text.RegularExpressions.Regex.Replace(html, @"<(script|style)[^>]*>.*?</\1>", " ",
            System.Text.RegularExpressions.RegexOptions.Singleline | System.Text.RegularExpressions.RegexOptions.IgnoreCase);
        text = System.Text.RegularExpressions.Regex.Replace(text, @"<[^>]+>", " ");
        text = System.Net.WebUtility.HtmlDecode(text);
        text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ");
        return text.Trim();
    }
}

public record SearchResult(string Title, string Snippet, string Url);

/// <summary>A simple in-memory notebook for the agent to store and retrieve research notes.</summary>
public sealed class Notebook
{
    private readonly List<NoteEntry> _notes = [];

    [Description("Saves a research note with a topic label and the content. Use this to record important findings.")]
    public string SaveNote(
        [Description("A short label for the note (e.g. 'key finding', 'statistic', 'source').")] string label,
        [Description("The content of the note.")] string content,
        [Description("The source URL, if applicable.")] string? sourceUrl = null)
    {
        _notes.Add(new NoteEntry(label, content, sourceUrl));
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieves all saved research notes.")]
    public IReadOnlyList<NoteEntry> GetNotes()
    {
        return _notes.AsReadOnly();
    }

    public void Clear() => _notes.Clear();
}

public record NoteEntry(string Label, string Content, string? SourceUrl);

